class ResponseScorer:
    def __init__(self, job_description_data, resume_data):
        self.job_description_data = job_description_data
        self.resume_data = resume_data

    def score_response(self, question, response):
        score = 0
        feedback = []

        # Skill-based scoring
        for skill in self.job_description_data.get('skills', []):
            if skill.lower() in question.lower():  # Check if the question is about a specific skill
                if skill.lower() in response.lower():
                    score += 5
                    feedback.append(f"Demonstrated knowledge of {skill}.")
                else:
                    score -= 2
                    feedback.append(f"Could elaborate more on {skill}.")

        # Experience-based scoring
        experience_years = self.job_description_data.get('experience')
        if experience_years and "experience" in question.lower():
            # Simple check for mentioning years of experience
            if str(experience_years) in response:
                score += 3
                feedback.append("Addressed experience requirements.")
            else:
                score -= 1
                feedback.append("Ensure to address your total years of experience.")

        # Resume-based scoring (matching resume content with response)
        for past_experience in self.resume_data.get('experience', []):
            if past_experience['job_title'].lower() in question.lower() or past_experience['company'].lower() in question.lower():
                if past_experience['job_title'].lower() in response.lower() or past_experience['company'].lower() in response.lower():
                    score += 4
                    feedback.append("Response aligns with resume details.")
                else:
                    score -= 2
                    feedback.append("Consider referencing resume details more explicitly.")

        #Generic positive/negative keywords
        if any(keyword in response.lower() for keyword in ['excellent', 'strong', 'proficient', 'adept']):
            score += 2
            feedback.append("Positive keywords detected.")

        if any(keyword in response.lower() for keyword in ['struggled', 'difficulty', 'limited']):
            score -= 1
            feedback.append("Negative keywords detected; clarify challenges with solutions")

        return max(0, min(10, score)), feedback  # Scale score between 0 and 10


if __name__ == '__main__':
    # Example Usage:
    job_description_data = {
        'skills': ['Python', 'Java', 'Machine Learning'],
        'experience': 5
    }

    resume_data = {
        'experience': [
            {'job_title': 'Software Engineer', 'company': 'Acme Corp'},
            {'job_title': 'Data Scientist', 'company': 'Beta Corp'}
        ],
        'skills': ['Python', 'SQL']
    }

    scorer = ResponseScorer(job_description_data, resume_data)

    question1 = "Tell me about your experience with Python."
    response1 = "I have 5 years of experience using Python for web development and data analysis."
    score1, feedback1 = scorer.score_response(question1, response1)
    print(f"Question: {question1}\nResponse: {response1}\nScore: {score1}\nFeedback: {feedback1}\n")

    question2 = "What were your key accomplishments as a Software Engineer at Acme Corp?"
    response2 = "I led a team that developed a new feature using Java."
    score2, feedback2 = scorer.score_response(question2, response2)
    print(f"Question: {question2}\nResponse: {response2}\nScore: {score2}\nFeedback: {feedback2}\n")
